  1→import type {
  2→	ModelTokensTrendData,
  3→	OverviewKPIs,
  4→	UsageTrendData,
  5→} from "@rudel/api-routes";
  6→import { user } from "@rudel/sql-schema";
  7→import { eq } from "drizzle-orm";
  8→import {
  9→	buildDateFilter,
 10→	escapeString,
 11→	queryClickhouse,
 12→} from "../clickhouse.js";
 13→import { db } from "../db.js";
 14→
 15→export interface Insight {
 16→	type: "trend" | "performer" | "alert" | "info";
 17→	severity: "positive" | "warning" | "negative" | "info";
 18→	message: string;
 19→	link: string;
 20→}
 21→
 22→/**
 23→ * Get overview KPI counts: distinct users, sessions, projects, subagents, skills, slash commands
 24→ */
 25→export async function getOverviewKPIs(
 26→	orgId: string,
 27→	days = 7,
 28→): Promise<OverviewKPIs> {
 29→	const org = escapeString(orgId);
 30→	const dateFilter = buildDateFilter(days);
 31→
 32→	const query = `
 33→    SELECT
 34→      uniq(user_id) as distinct_users,
 35→      count() as distinct_sessions,
 36→      uniq(if(git_remote != '', git_remote, if(repository != '', repository, project_path))) as distinct_projects,
 37→      (SELECT uniqExact(val) FROM rudel.session_analytics ARRAY JOIN subagent_types as val WHERE ${buildDateFilter(days)} AND organization_id = '${org}' AND val != '') as distinct_subagents,
 38→      (SELECT uniqExact(val) FROM rudel.session_analytics ARRAY JOIN skills as val WHERE ${buildDateFilter(days)} AND organization_id = '${org}' AND val != '') as distinct_skills,
 39→      (SELECT uniqExact(val) FROM rudel.session_analytics ARRAY JOIN slash_commands as val WHERE ${buildDateFilter(days)} AND organization_id = '${org}' AND val != '') as distinct_slash_commands,
 40→      (SELECT count() FROM rudel.session_analytics WHERE organization_id = '${org}') as total_sessions
 41→    FROM rudel.session_analytics
 42→    WHERE ${dateFilter}
 43→      AND organization_id = '${org}'
 44→  `;
 45→
 46→	const result = await queryClickhouse<OverviewKPIs>(query);
 47→	const row = result[0];
 48→	if (!row) {
 49→		return {
 50→			distinct_users: 0,
 51→			distinct_sessions: 0,
 52→			distinct_projects: 0,
 53→			distinct_subagents: 0,
 54→			distinct_skills: 0,
 55→			distinct_slash_commands: 0,
 56→			total_sessions: 0,
 57→		};
 58→	}
 59→	// ClickHouse returns UInt64 as strings when output_format_json_quote_64bit_integers is true (the default)
 60→	return {
 61→		distinct_users: Number(row.distinct_users),
 62→		distinct_sessions: Number(row.distinct_sessions),
 63→		distinct_projects: Number(row.distinct_projects),
 64→		distinct_subagents: Number(row.distinct_subagents),
 65→		distinct_skills: Number(row.distinct_skills),
 66→		distinct_slash_commands: Number(row.distinct_slash_commands),
 67→		total_sessions: Number(row.total_sessions),
 68→	};
 69→}
 70→
 71→/**
 72→ * Get token usage broken down by model and day
 73→ */
 74→export async function getModelTokensTrend(
 75→	orgId: string,
 76→	days = 30,
 77→): Promise<ModelTokensTrendData[]> {
 78→	const org = escapeString(orgId);
 79→	const dateFilter = buildDateFilter(days);
 80→
 81→	const query = `
 82→    SELECT
 83→      toDate(session_date) as date,
 84→      model_used as model,
 85→      sum(total_tokens) as total_tokens,
 86→      sum(input_tokens) as input_tokens,
 87→      sum(output_tokens) as output_tokens
 88→    FROM rudel.session_analytics
 89→    WHERE ${dateFilter}
 90→      AND organization_id = '${org}'
 91→      AND model_used != ''
 92→      AND model_used != 'unknown'
 93→    GROUP BY date, model
 94→    ORDER BY date ASC, total_tokens DESC
 95→  `;
 96→
 97→	return queryClickhouse<ModelTokensTrendData>(query);
 98→}
 99→
100→/**
101→ * Get detailed usage trend data aggregated by day
102→ */
103→export async function getUsageTrendDetailed(
104→	orgId: string,
105→	days = 30,
106→): Promise<UsageTrendData[]> {
107→	const org = escapeString(orgId);
108→	const dateFilter = buildDateFilter(days);
109→
110→	const query = `
111→    SELECT
112→      toDate(session_date) as date,
113→      count() as sessions,
114→      uniq(user_id) as active_users,
115→      round(sum(actual_duration_min) / 60, 2) as total_hours,
116→      sum(total_tokens) as total_tokens
117→    FROM rudel.session_analytics
118→    WHERE ${dateFilter}
119→      AND organization_id = '${org}'
120→    GROUP BY date
121→    ORDER BY date ASC
122→  `;
123→
124→	return queryClickhouse<UsageTrendData>(query);
125→}
126→
127→/**
128→ * Generate rule-based insights from current data
129→ */
130→export async function getOverviewInsights(
131→	orgId: string,
132→	days = 7,
133→): Promise<Insight[]> {
134→	const org = escapeString(orgId);
135→	const insights: Insight[] = [];
136→
137→	const currentPeriodQuery = `
138→    SELECT
139→      count() as total_sessions,
140→      uniq(user_id) as total_users,
141→      round(avg(actual_duration_min), 2) as avg_duration_min
142→    FROM rudel.session_analytics
143→    WHERE ${buildDateFilter(days)}
144→      AND organization_id = '${org}'
145→  `;
146→
147→	const previousDays = Number(days) * 2;
148→	const previousPeriodQuery = `
149→    SELECT
150→      count() as total_sessions,
151→      uniq(user_id) as total_users,
152→      round(avg(actual_duration_min), 2) as avg_duration_min
153→    FROM rudel.session_analytics
154→    WHERE session_date >= now64(3) - INTERVAL ${previousDays} DAY
155→      AND session_date < now64(3) - INTERVAL ${Number(days)} DAY
156→      AND organization_id = '${org}'
157→  `;
158→
159→	interface PeriodStats {
160→		total_sessions: number;
161→		total_users: number;
162→		avg_duration_min: number;
163→	}
164→
165→	const [currentData, previousData] = await Promise.all([
166→		queryClickhouse<PeriodStats>(currentPeriodQuery),
167→		queryClickhouse<PeriodStats>(previousPeriodQuery),
168→	]);
169→
170→	const current = currentData[0];
171→	const previous = previousData[0] || { total_sessions: 0 };
172→
173→	// Insight 1: Session trend analysis
174→	if (current && previous) {
175→		const sessionChange =
176→			previous.total_sessions > 0
177→				? ((current.total_sessions - previous.total_sessions) /
178→						previous.total_sessions) *
