): Promise<UsageTrendData[]> {
	const org = escapeString(orgId);
	const dateFilter = buildAbsoluteDateFilter(startDate, endDate);

	const query = `
    SELECT
      toDate(session_date) as date,
      count() as sessions,
      uniq(user_id) as active_users,
